```typescript
function solve(m: number, n: number, waitCost: number[][]): number {
    const maxSteps = m + n;
    const dp = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(maxSteps + 1).fill(Infinity)));
    dp[0][0][0] = 1;

    for (let s = 0; s < maxSteps; s++) {
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (dp[i][j][s] === Infinity) continue;
                if (s % 2 === 0) {
                    // Move right
                    if (j + 1 < n) {
                        const newI = i;
                        const newJ = j + 1;
                        const newCost = dp[i][j][s] + (i + 1) * (newJ + 1);
                        if (newCost < dp[newI][newJ][s + 1]) {
                            dp[newI][newJ][s + 1] = newCost;
                        }
                    }
                    // Move down
                    if (i + 1 < m) {
                        const newI = i + 1;
                        const newJ = j;
                        const newCost = dp[i][j][s] + (newI + 1) * (j + 1);
                        if (newCost < dp[newI][newJ][s + 1]) {
                            dp[newI][newJ][s + 1] = newCost;
                        }
                    }
                } else {
                    // Wait
                    const newCost = dp[i][j][s] + waitCost[i][j];
                    if (newCost < dp[i][j][s + 1]) {
                        dp[i][j][s + 1] = newCost;
                    }
                }
            }
        }
    }

    let result = Infinity;
    for (let s = 0; s <= maxSteps; s++) {
        result = Math.min(result, dp[m - 1][n - 1][s]);
    }
    return result;
}
