public static long solve(long m, long n, long[][] waitCost) {
    int maxSteps = (int) (m + n);
    long[][][] dp = new long[m][n][maxSteps + 1];
    // Initialize with infinity
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            for (int s = 0; s <= maxSteps; s++) {
                dp[i][j][s] = Long.MAX_VALUE;
            }
        }
    }
    dp[0][0][0] = 1;

    for (int s = 0; s < maxSteps; s++) {
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (dp[i][j][s] == Long.MAX_VALUE) continue;
                if (s % 2 == 0) {
                    // move right or down
                    if (j + 1 < n) {
                        int newI = i;
                        int newJ = j + 1;
                        long newCost = dp[i][j][s] + (i + 1) * (newJ + 1);
                        if (newCost < dp[newI][newJ][s + 1]) {
                            dp[newI][newJ][s + 1] = newCost;
                        }
                    }
                    if (i + 1 < m) {
                        int newI = i + 1;
                        int newJ = j;
                        long newCost = dp[i][j][s] + (newI + 1) * (j + 1);
                        if (newCost < dp[newI][newJ][s + 1]) {
                            dp[newI][newJ][s + 1] = newCost;
                        }
                    }
                } else {
                    // wait
                    long newCost = dp[i][j][s] + waitCost[i][j];
                    if (newCost < dp[i][j][s + 1]) {
                        dp[i][j][s + 1] = newCost;
                    }
                }
            }
        }
    }

    long result = Long.MAX_VALUE;
    for (int s = 0; s <= maxSteps; s++) {
        result = Math.min(result, dp[m - 1][n - 1][s]);
    }
    return result;
}

